import take from "../../../../../../../../../../../subject_repositories/pull-stream/throughs/take.js";

describe("take through - propagates end signal from source", () => {
  it("should call the callback when source signals end during read", (done) => {
    const takeThrough = take(10); // take up to 10 items, more than source provides

    let count = 0;
    const source = (end: any, cb: Function) => {
      if (end) { cb(end); return; }
      count++;
      if (count > 2) { cb(true); } // end after 2 items
      else { cb(null, count); }
    };

    const through = takeThrough(source);
    const results: number[] = [];

    function drain() {
      through(false, (end: any, data: any) => {
        if (end) {
          expect(results).toEqual([1, 2]);
          done();
          return;
        }
        results.push(data);
        drain();
      });
    }

    drain();
  });
});
